+                <button type="button" class="btn btn-primary" @onclick="CheckAvailabilityAsync"
+                        disabled="@IsSubmitting">
+                    @(IsSubmitting ? "Checking…" : "Check Availability")
+                </button>
+            </div>
+        </fieldset>
+    }
+
+    @if (IsConfirmed)
+    {
+        <div class="alert alert-success mt-3">
+            Appointment booked successfully!
+        </div>
+    }
+</EditForm>
+
+@code {
+    private BookAppointmentModel Model { get; set; } = new();
+    private EditContext? editContext;
+    private ValidationMessageStore? messageStore;
+
+    private bool ShowStep2 { get; set; }
+    private bool IsSubmitting { get; set; }
+    private bool IsConfirmed { get; set; }
+
+    private List<string> Doctors { get; set; } = [];
+    private List<string> AvailableSlots { get; set; } = [];
+
+    protected override async Task OnInitializedAsync()
+    {
+        editContext = new EditContext(Model);
+        messageStore = new ValidationMessageStore(editContext);
+        Doctors = await AppointmentSvc.GetDoctorsAsync();
+    }
+
+    /// <summary>Validate step-1 fields and move forward.</summary>
+    private void ProceedToStep2Async()
+    {
+        messageStore?.Clear();
+
+        // Validate only step-1 fields
+        var isValid = true;
+
+        if (string.IsNullOrWhiteSpace(Model.PatientName))
+        {
+            messageStore!.Add(() => Model.PatientName, "Patient name is required.");
+            isValid = false;
+        }
+        if (string.IsNullOrWhiteSpace(Model.Email))
+        {
+            messageStore!.Add(() => Model.Email, "Email is required.");
+            isValid = false;
+        }
+        else if (!new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email))
+        {
+            messageStore!.Add(() => Model.Email, "Invalid email format.");
+            isValid = false;
+        }
+        if (string.IsNullOrWhiteSpace(Model.Phone))
+        {
+            messageStore!.Add(() => Model.Phone, "Phone number is required.");
+            isValid = false;
+        }
+        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
+        {
+            messageStore!.Add(() => Model.InsuranceProvider, "Insurance provider is required.");
+            isValid = false;
+        }
+
+        editContext!.NotifyValidationStateChanged();
+
+        if (isValid)
+        {
+            ShowStep2 = true;
+        }
+    }
+
+    private void BackToStep1()
+    {
+        ShowStep2 = false;
+        messageStore?.Clear();
+        editContext!.NotifyValidationStateChanged();
+    }
+
+    /// <summary>Reload available time slots when doctor or date changes.</summary>
+    private async Task OnDoctorOrDateChangedAsync()
+    {
+        // Clear previous slot-related errors
+        messageStore?.Clear(editContext!.Field(nameof(Model.TimeSlot)));
+        editContext!.NotifyValidationStateChanged();
+
+        Model.TimeSlot = string.Empty;
+
+        if (!string.IsNullOrEmpty(Model.PreferredDoctor) && Model.AppointmentDate.HasValue)
+        {
+            AvailableSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
+                Model.PreferredDoctor, Model.AppointmentDate.Value);
+        }
+        else
+        {
+            AvailableSlots = [];
+        }
+    }
+
+    /// <summary>Run server-side validation and, if clean, confirm the booking.</summary>
+    private async Task CheckAvailabilityAsync()
+    {
+        messageStore?.Clear();
+        editContext!.NotifyValidationStateChanged();
+
+        // Client-side validation of step-2 fields
+        var step2Valid = true;
+
+        if (string.IsNullOrWhiteSpace(Model.PreferredDoctor))
+        {
+            messageStore!.Add(() => Model.PreferredDoctor, "Please select a doctor.");
+            step2Valid = false;
+        }
+        if (!Model.AppointmentDate.HasValue)
+        {
+            messageStore!.Add(() => Model.AppointmentDate, "Date is required.");
+            step2Valid = false;
+        }
+        else if (Model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
+        {
+            messageStore!.Add(() => Model.AppointmentDate, "Date must be in the future.");
+            step2Valid = false;
+        }
+        if (string.IsNullOrWhiteSpace(Model.TimeSlot))
+        {
+            messageStore!.Add(() => Model.TimeSlot, "Please select a time slot.");
+            step2Valid = false;
+        }
+        if (string.IsNullOrWhiteSpace(Model.ReasonForVisit))
+        {
+            messageStore!.Add(() => Model.ReasonForVisit, "Reason for visit is required.");
+            step2Valid = false;
+        }
+        else if (Model.ReasonForVisit.Length > 500)
+        {
+            messageStore!.Add(() => Model.ReasonForVisit, "Reason cannot exceed 500 characters.");
+            step2Valid = false;
+        }
+
+        if (!step2Valid)
+        {
+            editContext!.NotifyValidationStateChanged();
+            return;
+        }
+
+        IsSubmitting = true;
+
+        try
+        {
+            var serverErrors = await AppointmentSvc.ValidatePatientAsync(
+                Model.Email,
+                Model.InsuranceProvider,
+                Model.PreferredDoctor,
+                Model.TimeSlot);
+
+            if (serverErrors.Count > 0)
+            {
+                foreach (var (field, message) in serverErrors)
+                {
+                    messageStore!.Add(editContext!.Field(field), message);
+                }
+                editContext!.NotifyValidationStateChanged();
+                return;
+            }
+
+            // All validations passed — confirm booking
+            IsConfirmed = true;
+        }
+        finally
+        {
+            IsSubmitting = false;
+        }
+    }
+
+    private Task HandleSubmitAsync()
+    {
+        // The form submit is not used directly; booking flows through CheckAvailabilityAsync.
+        return Task.CompletedTask;
+    }
+}
+

